//-------------------------------------------------------------------------
// Constructor
//-------------------------------------------------------------------------
MRFProcessToolsCmd::MRFProcessToolsCmd(CATUnicodeString configFileName, CATUnicodeString configFolderName, CATBaseUnknown_var spSelectedRootGeomSet) : 
CATStateCommand ("MRFProcessToolsCmd", CATDlgEngOneShot, CATCommandModeShared)
//  Valid states are CATDlgEngOneShot and CATDlgEngRepeat
, _pMRFProcessToolsDlg(NULL)
, _pApplicationFrame(NULL)
, _pEditor(NULL)
, _pHSO(NULL)
, _pISO(NULL)
, _spCBUOnCurrObject(NULL)
, _spMechanicalPart(NULL_var)
, _spPrtCont(NULL_var)
, _spGSMFactory(NULL_var)
, _spMRFGSDFactory(NULL_var)
, _spNESCurveFeat(NULL_var)
, _spCkeRelFact(NULL_var)
,_spGSMTool_RootSet(NULL_var)
, _spProcessToolGeomSet(NULL_var)
, _spXYPlane(NULL_var)
, _pFrameParamToHide(NULL)
, _spParamEditedFromFrame(NULL_var)
, _spGeoFactory(NULL_var)

{
	//--------------New Method ------------------------------------------------//
	if (spSelectedRootGeomSet)
	{
		_spProcessToolGeomSet = spSelectedRootGeomSet;
	}
	_ConfigFilename = configFileName;
	_pDialogAgentGeomSetSel = NULL;
	_pDialogAgentXYPlaneSel = NULL;
	_pPathElementAgentGeomSetSel = NULL;
	_pPathElementAgentXYPlaneSel = NULL;
	_pPathElementProcessGeomSet = NULL;
	_pPathElementXYPlane = NULL;
	_pExcelFileDialog = NULL;
	_pListOfConfigFileInfo.RemoveAll();
	_pListOfGenericDialog.RemoveAll();
	_pListOfProcessToolsOperationsBaseClass.RemoveAll();
	//-------------------------------------------------------------//
	_pApplicationFrame = CATApplicationFrame::GetFrame();
	_pEditor = CATFrmEditor::GetCurrentEditor();
	if (NULL != _pEditor)
	{
		_pHSO = _pEditor->GetHSO();
		_pISO = _pEditor->GetISO();

		CATPathElement  oActivePath = _pEditor->GetUIActiveObject();
		oActivePath.InitToLeafElement();
		_spCBUOnCurrObject = oActivePath.NextFatherElement();

		CATUnicodeString objName;
		if (!!_spCBUOnCurrObject)
			objName = MRFGenericUtils::GetAliasName(_spCBUOnCurrObject);

		if (NULL_var != _spCBUOnCurrObject)
		{
			CATIMmiUsePrtPart * piPrtPart = NULL;
			_spCBUOnCurrObject->QueryInterface(IID_CATIMmiUsePrtPart, (void**)&piPrtPart);
			if (NULL != piPrtPart && NULL_var == _spMechanicalPart)
			{
				_spMechanicalPart = piPrtPart;
				CATListValCATIMmiMechanicalFeature_var spListOfPlanes;
				piPrtPart->RetrieveReferencePlanes(spListOfPlanes);

				if (spListOfPlanes.Size() > 0)
					_spXYPlane = spListOfPlanes[1];

				if (NULL_var != _spXYPlane)
					MRFGenericUtils::GetUIActivePathElement(_pEditor, _spXYPlane, _pPathElementXYPlane);

				piPrtPart->Release();  piPrtPart = NULL;
			}

			if (NULL_var != _spMechanicalPart)
			{
				_spMechanicalPart->GetPrtContainer(_spPrtCont);
				if (NULL_var != _spPrtCont)
				{
					_spGSMFactory = _spPrtCont;	
					_spCkeRelFact = _spPrtCont;
					_spMRFGSDFactory = _spPrtCont;
					//HRESULT rc = _spPrtCont->QueryInterface(IID_MRFIGSDFactory, (void**)& _spMRFGSDFactory);
					CATICGMContainer_var spCGMContainer;
					_spPrtCont->GetGeometricalContainer(spCGMContainer);

					if (spCGMContainer != NULL_var && NULL_var == _spGeoFactory)
						spCGMContainer->QueryInterface(IID_CATGeoFactory, (void**)&_spGeoFactory);


				}

				if(spSelectedRootGeomSet == NULL_var) //Check this condition for create or edit mode. If Edit mode this will be true, in create mode it will be false;
					this->CreateGeometricalSetInAStructure(_spMechanicalPart); //it creates the root geometrical set in a part
			}
		}
	}

	_pMRFProcessToolsDlg = new MRFProcessToolsDlg();

	//Create object for this class in cmd at last of constructor

	_udfTypeIndexFromCombo = 1;
	_udfTypeIndexFromCombo_Previous = 1;
	_multiListIndexSelectedForEdit = 0;

	this->ReadNLSTabInfoFromConfigFile(configFileName, configFolderName); //Reads the Config file while the command launches and helps to buil;d gthe UI

}

