//-------------------------------------------------------------------------
// BuildGraph()
//-------------------------------------------------------------------------
void MRFProcessToolsCmd::BuildGraph()
{

	if (_pMRFProcessToolsDlg)
	{

		_pMRFProcessToolsDlg->Build();
		_pMRFProcessToolsDlg->SetVisibility(CATDlgShow);

		if(!!_spGSMTool_RootSet)
			_pMRFProcessToolsDlg->UpdateSelectorList(FromProcessGeomSetSelector, MRFGenericUtils::GetAliasName(_spGSMTool_RootSet));


		AddAnalyseNotificationCB(_pMRFProcessToolsDlg, _pMRFProcessToolsDlg->GetDiaOKNotification(), (CATCommandMethod)&MRFProcessToolsCmd::ActionOK, NULL);
		AddAnalyseNotificationCB(_pMRFProcessToolsDlg, _pMRFProcessToolsDlg->GetDiaCANCELNotification(), (CATCommandMethod)&MRFProcessToolsCmd::ActionClose, NULL);
		AddAnalyseNotificationCB(_pMRFProcessToolsDlg, _pMRFProcessToolsDlg->GetWindCloseNotification(), (CATCommandMethod)&MRFProcessToolsCmd::ActionClose, NULL);
		AddAnalyseNotificationCB(_pMRFProcessToolsDlg, _pMRFProcessToolsDlg->GetDiaPREVIEWNotification(), (CATCommandMethod)&MRFProcessToolsCmd::ActionOne, NULL);
		
		CATDlgPushButton* pPushButtonUpdate = NULL;
		pPushButtonUpdate = _pMRFProcessToolsDlg->GetPushButton_Update();
		if (pPushButtonUpdate)
		{
			AddAnalyseNotificationCB(pPushButtonUpdate, pPushButtonUpdate->GetPushBActivateNotification(), (CATCommandMethod)&MRFProcessToolsCmd::UpdatePackage, NULL);
		}
		
		CATDlgPushButton* pPushButtonNextTab = NULL;
		pPushButtonNextTab = _pMRFProcessToolsDlg->GetPushButton_NextTab();
		if (pPushButtonNextTab)
		{
			AddAnalyseNotificationCB(pPushButtonNextTab, pPushButtonNextTab->GetPushBActivateNotification(), (CATCommandMethod)&MRFProcessToolsCmd::NavigateTabPage, From_NextTab);
		}
		
		CATDlgPushButton* pPushButtonPrevTab = NULL;
		pPushButtonPrevTab = _pMRFProcessToolsDlg->GetPushButton_PrevTab();
		if (pPushButtonPrevTab)
		{
			AddAnalyseNotificationCB(pPushButtonPrevTab, pPushButtonPrevTab->GetPushBActivateNotification(), (CATCommandMethod)&MRFProcessToolsCmd::NavigateTabPage, From_PrevTab);
		}

		CATDlgTabContainer *pTabContainer = NULL;
		pTabContainer = _pMRFProcessToolsDlg->GetTabContainer();
		if (pTabContainer)
		{
			AddAnalyseNotificationCB(pTabContainer, pTabContainer->GetTabSelectNotification(), (CATCommandMethod)&MRFProcessToolsCmd::OnComboBeltSelected, From_PrevTab);

		}
		//----------------------------New Method Starts--------------------------------------//

		_pPathElementAgentGeomSetSel = new CATPathElementAgent("GeomSet Sel PathElement Agent");
		if (_pPathElementAgentGeomSetSel)
		{
			_pPathElementAgentGeomSetSel->AddOrderedElementType("CATIBodyRequest");
			_pPathElementAgentGeomSetSel->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);
		}

		_pDialogAgentGeomSetSel = new CATDialogAgent("GeomSet Sel Agent");
		if (_pDialogAgentGeomSetSel)
		{
			CATDlgSelectorList* pGeomSetSelList = _pMRFProcessToolsDlg->GetSelectorListProcessToolGeomSet();
			if (pGeomSetSelList)
			{
				_pDialogAgentGeomSetSel->AcceptOnNotify(pGeomSetSelList, pGeomSetSelList->GetListSelectNotification());

			}
		}
		
		_pPathElementAgentXYPlaneSel = new CATPathElementAgent("XYPlane Sel PathElement Agent");
		if (_pPathElementAgentXYPlaneSel)
		{
			_pPathElementAgentXYPlaneSel->AddOrderedElementType("CATIGSMUsePlane");
			_pPathElementAgentXYPlaneSel->AddOrderedElementType("CATPlane");
			_pPathElementAgentXYPlaneSel->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);
		}

		_pDialogAgentXYPlaneSel = new CATDialogAgent("GeomSet Sel Agent");
		if (_pDialogAgentXYPlaneSel)
		{
			CATDlgSelectorList* pXYPlaneSelList = _pMRFProcessToolsDlg->GetSelectorListXYPlane();
			if (pXYPlaneSelList)
			{
				_pDialogAgentXYPlaneSel->AcceptOnNotify(pXYPlaneSelList, pXYPlaneSelList->GetListSelectNotification());

			}
		}
		
		/*CATDialogState *pGeomSetSelState = NULL;
		pGeomSetSelState = GetInitialState("GeomSet Select State");
		if (pGeomSetSelState)
		{
			pGeomSetSelState->AddDialogAgent(_pDialogAgentGeomSetSel);
			pGeomSetSelState->AddDialogAgent(_pDialogAgentXYPlaneSel);
			pGeomSetSelState->AddDialogAgent(_pPathElementAgentGeomSetSel);
		}
		*/
		CATDialogState *pXYPlaneSelState = NULL;
		pXYPlaneSelState = GetInitialState("XYPlane Select State");
		if (pXYPlaneSelState)
		{
			pXYPlaneSelState->AddDialogAgent(_pDialogAgentXYPlaneSel);
			pXYPlaneSelState->AddDialogAgent(_pPathElementAgentXYPlaneSel);
		}

		//----------------------------------------For Selection Starts------------------------------------------------//
					
		CATDlgSelectorList* pXYPlaneSelList = _pMRFProcessToolsDlg->GetSelectorListXYPlane();	
		CATCommandClientData selListXYPlaneLoc(pXYPlaneSelList);
		AddTransition(pXYPlaneSelState, pXYPlaneSelState, IsOutputSetCondition(_pPathElementAgentXYPlaneSel),
			Action((ActionMethod)&MRFProcessToolsCmd::OnObjectSelection, NULL, NULL, selListXYPlaneLoc));

		//------------------------------------------For Selection Ends----------------------------------------------------------//

		//-----------For Transition Starts----------------//

		AddTransition(pXYPlaneSelState, pXYPlaneSelState, IsOutputSetCondition(_pDialogAgentXYPlaneSel),
			Action((ActionMethod)&MRFProcessToolsCmd::OnSelectorListSelected, NULL, NULL, selListXYPlaneLoc));

		//------------------For Transition Ends-------------------------------------//

		this->BuildUIFromConfigFile(); //Build the number of instances of Generic dialog class and set it in the main dialog
		
		if(!!_spProcessToolGeomSet)
			this->ReadRootGeomSet(_spProcessToolGeomSet);
		//----------------------------New Method Ends--------------------------------------//

	}




}


//-------------------------------------------------------------------------
// ActionOne ()
//-------------------------------------------------------------------------
void MRFProcessToolsCmd::ActionOne(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
// TODO: Define the action associated with the transition
// ------------------------------------------------------
	if (_pMRFProcessToolsDlg)
	{
		int tabCount = _pMRFProcessToolsDlg->GetTabContainer()->GetPageCount();

		if (tabCount <= 0)
			return;
		CATBody_var spBodyOfUDF;
		if(!!_spGeoFactory)
			spBodyOfUDF = _spGeoFactory->CreateBody();
		
		for (int i = 1; i <= tabCount; i++)
		{
			if (_pListOfProcessToolsOperationsBaseClass.Size() > 0 && _pListOfGenericDialog.Size() > 0)
			{
				ProcessToolOperationsBaseClass* pOperationBaseClass = (ProcessToolOperationsBaseClass*)_pListOfProcessToolsOperationsBaseClass[i];
				GenericTabDialog* pTabDialog = (GenericTabDialog*)_pListOfGenericDialog[i];
				CATBaseUnknown_var udfInst;
				if (pOperationBaseClass && pTabDialog)
				{

					udfInst = pOperationBaseClass->GetUDFInstance();
					if (udfInst)
					{
						CATListValCATBaseUnknown_var spUDFOutputFeat = pOperationBaseClass->GetUDFOutputInfo(udfInst);

						for (int k = 1; k <= spUDFOutputFeat.Size(); k++)
						{
							CATBody_var spBodyOfUDFLoc;

							CATBaseUnknown_var spOutputFeat = spUDFOutputFeat[k];
							if (spOutputFeat)
							{
								MRFGenericUtils::GetBodyOfObject(spOutputFeat, spBodyOfUDFLoc);


								CATListPtrCATDomain lidtOfDomain;
								if (!!spBodyOfUDFLoc)
									spBodyOfUDFLoc->GetAllDomains(1, 3, lidtOfDomain);

								for (int j = 1; j <= lidtOfDomain.Size(); j++)
								{
									CATDomain* pDomain = lidtOfDomain[j];
									if (pDomain)
										spBodyOfUDF->AddDomain(pDomain);
								}


							}
							else
								continue;
						}
					}
					else
						continue;


				}
			}
		}
		if (!!spBodyOfUDF)
		{
			MRFGenericUtils::ReframeOnObject(spBodyOfUDF);
			_spGeoFactory->Remove(spBodyOfUDF);
			spBodyOfUDF = NULL;
		}
		

	}

return;
}

