//-------------------------------------------------------------------------
// MRFProcessToolsCmd::OnSelectorListSelected
//Function: When user clicks to select the selector list in dialog, allows agent to be active, and the selected object is highlighted will be displayed in this list.
//------------------------------------------------------------------------
CATBoolean MRFProcessToolsCmd::OnSelectorListSelected(void* iUsefulData)
{
	char *temp = (char*)iUsefulData;
	
	CATDlgSelectorList *pSelectorList = (CATDlgSelectorList *)iUsefulData;
	if (!pSelectorList)
		return FALSE;



	CATString selListName = pSelectorList->GetName();

	if (_pMRFProcessToolsDlg)
		_pMRFProcessToolsDlg->ClearOtherSelections(selListName);

	CATDialogAgent * pDialoAgent = NULL;
	CATPathElement * pPathElement = NULL;
	
	if (NULL != _pHSO)
	{
		_pHSO->Empty();
	}

	if (selListName == FromProcessGeomSetSelector)
	{
		pDialoAgent = _pDialogAgentGeomSetSel;
		pPathElement = _pPathElementProcessGeomSet;
		if (!!_pMRFProcessToolsDlg)
			_pMRFProcessToolsDlg->ClearOtherSelections(temp);

	}
	else if (selListName == FromProcessXYPlaneSelector)
	{
		pDialoAgent = _pDialogAgentXYPlaneSel;
		pPathElement = _pPathElementXYPlane;

		if (!!_pMRFProcessToolsDlg)
			_pMRFProcessToolsDlg->ClearOtherSelections(temp);


	}

	if (NULL != _pHSO)
	{

		if (NULL != pPathElement && 0 == _pHSO->IsMember(pPathElement))
		{
			_pHSO->AddElement(pPathElement);
		}

	}

	if (!!pDialoAgent)
		pDialoAgent->InitializeAcquisition();

	return TRUE;
}
//-------------------------------------------------------------------------
// MRFProcessToolsCmd::OnObjectSelection
//Function: When user selects the object, the agent is initialized and the select object pathElement is assigned
//------------------------------------------------------------------------
CATBoolean MRFProcessToolsCmd::OnObjectSelection(void* iUsefulData)
{
	char * pstrAction = (char *)iUsefulData;

	//CATString strAction(pstrAction);

	CATDlgSelectorList *pSelectorList = (CATDlgSelectorList *)iUsefulData;
	if (!pSelectorList)
		return FALSE;

	CATString selListName = pSelectorList->GetName();

	CATPathElementAgent *pPathElemAgent = NULL;
	CATBaseUnknown_var spSelectedElement;
	CATPathElement * pPathElement = NULL;


	if (selListName == FromProcessGeomSetSelector)
	{
		pPathElemAgent = _pPathElementAgentGeomSetSel;

	}
	else if (selListName == FromProcessXYPlaneSelector)
	{
		pPathElemAgent = _pPathElementAgentXYPlaneSel;
	}

	if (!!pPathElemAgent)
	{
		pPathElement = pPathElemAgent->GetValue();
		if (NULL != pPathElement)
		{
			CATUnicodeString strAlias = "";
			spSelectedElement = pPathElement->CurrentElement();

			if (!spSelectedElement)
				return FALSE;

				CATUnicodeString strName;
				CATIAlias_var spAlias = spSelectedElement;
				if (NULL_var != spAlias)
				{
					strName = spAlias->GetAlias();

					_pMRFProcessToolsDlg->UpdateSelectorList(selListName, strName);

				}

			if (NULL_var != spSelectedElement)
			{
				if (NULL != _pHSO)
				{
					_pHSO->Empty();

					if (0 == _pHSO->IsMember(pPathElement))
						_pHSO->AddElement(pPathElement);
				}
			}
		}

		pPathElemAgent->InitializeAcquisition();
	}

	if (selListName == FromProcessGeomSetSelector)
	{
		_pPathElementProcessGeomSet = pPathElement;
		_spProcessToolGeomSet = spSelectedElement;

		/*if (!!_spProcessToolGeomSet)
			ReadRootGeomSet(_spProcessToolGeomSet);*/


	}
	else if (selListName == FromProcessXYPlaneSelector)
	{
		_pPathElementXYPlane = pPathElement;
		_spXYPlane = spSelectedElement;

	}

	return CATTrue;
}
//=======================OnComboBeltSelected=============================================================//
//  Function initiated On Combo Belt Selected
void MRFProcessToolsCmd::OnComboBeltSelected(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{

	if (_pMRFProcessToolsDlg)
	{
		int index = _pMRFProcessToolsDlg->GetTabContainer()->GetSelectedPage();

		if (index < 0)
			return;

		index = index + 1; //since tab index starts from 0 but the info of tab store in a ptr list where index starts from one so add one to its index;

		if (_pListOfProcessToolsOperationsBaseClass.Size() > 0 && _pListOfGenericDialog.Size() > 0)
		{
			ProcessToolOperationsBaseClass* pOperationBaseClass = (ProcessToolOperationsBaseClass*)_pListOfProcessToolsOperationsBaseClass[index];
			GenericTabDialog* pTabDialog = (GenericTabDialog*)_pListOfGenericDialog[index];

			if (pOperationBaseClass && pTabDialog)
			{
				int comboIndex = pTabDialog->GetComboBoxUDFType()->GetSelect();
				_udfTypeIndexFromCombo_Previous = _udfTypeIndexFromCombo; //before changing the current combo index store it in a previous udf index variable

				_udfTypeIndexFromCombo = comboIndex + 1; // 
				pOperationBaseClass->SetUDFIndexFromComboBox(_udfTypeIndexFromCombo);
				pOperationBaseClass->SetIndexUDFActive(_udfTypeIndexFromCombo);

				CATDlgMultiList *pInputParm = NULL, *pCalculatedParam = NULL;
				pInputParm = pTabDialog->GetMultiListInputParam();
				pCalculatedParam = pTabDialog->GetMultiListCalculatedParam();
				if (pInputParm && pCalculatedParam)
					pOperationBaseClass->GetUDFParametersInfo(pInputParm, pCalculatedParam);
			}
		}


	}
}
//=======================OnInstantiatePushButton_Belt_Clicked=============================================================//
//  Function helps to instantiate the UDF when pushbutton is clicked
void MRFProcessToolsCmd::OnInstantiatePushButton_Belt_Clicked(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	HRESULT rc = E_FAIL;
	char* temp = (char*)iUsefulData;

	if (_pMRFProcessToolsDlg)
	{
		int index = _pMRFProcessToolsDlg->GetTabContainer()->GetSelectedPage();

		if (index < 0)
			return;

		index = index + 1; //since tab index starts from 0 but the info of tab store in a ptr list where index starts from one so add one to its index;

		if (_pListOfProcessToolsOperationsBaseClass.Size() > 0 && _pListOfGenericDialog.Size() > 0)
		{
			ProcessToolOperationsBaseClass* pOperationBaseClass = (ProcessToolOperationsBaseClass*)_pListOfProcessToolsOperationsBaseClass[index];
			GenericTabDialog* pTabDialog = (GenericTabDialog*)_pListOfGenericDialog[index];

			if (pOperationBaseClass && pTabDialog)
			{
				if (!_spXYPlane)
				{
					MRFGenericUtils::ShowErrorMessage("Select XY Plane First then Click Instantiate\n");
					return;
				}
				if (pOperationBaseClass && !!_spPrtCont)
				{
					CATListValCATBaseUnknown_var listOfInputsToReplace;
					listOfInputsToReplace.Append(_spXYPlane); //for any package xyplane will be pased as one input to set. If UDF is not taking the xy plane as input then it will be removed from list in the base class.

					CATListValCATBaseUnknown_var listOfUDFInputParmsPub, listOfOutputFeatPub;

					//The below for loop helps to get the previous package Insatntiated UDF's parameters and features which are published.
					// The dependancy index is stored in base class if required iterate and get only the dependancy packages UDF in future.(For performance improvement in future)
					for (int i = 1; i < index; i++) // check i for lass than index, reason: index refers to current package, so to check only the prev package give condition like that.
					{
						ProcessToolOperationsBaseClass* pOperationBaseClass_Prev = (ProcessToolOperationsBaseClass*)_pListOfProcessToolsOperationsBaseClass[i];
						if (pOperationBaseClass_Prev)
						{
							pOperationBaseClass_Prev->GetActiveUDFParamsAndFeatPublished(listOfUDFInputParmsPub, listOfOutputFeatPub); //retrieves the list of input params and output features of prev package

						}
					}

					pOperationBaseClass->SetUDFIndexFromComboBox(_udfTypeIndexFromCombo);
					pOperationBaseClass->SetPrevPackInputParmsAndOutputFeatList(listOfUDFInputParmsPub, listOfOutputFeatPub); //call this function before instantiating the UDF

					CATBaseUnknown_var spGeomSet_Existing;

					//MRFGenericUtils::CheckIfGeomSetAlreadyExist(_spMechanicalPart, pOperationBaseClass->GetTabName(), spGeomSet_Existing); //it will check under all geom set so removeing this method
					MRFGenericUtils::FindFeatureUnderGeomSet(_spGSMTool_RootSet, pOperationBaseClass->GetTabName(), spGeomSet_Existing); //it will check geom set under the selected root geom set

					if (!!spGeomSet_Existing)
						pOperationBaseClass->SetGeometricalSet(spGeomSet_Existing);
					else if (!!_spGSMTool_RootSet)
						pOperationBaseClass->CreateGeometricalSetInAStructure(_spGSMTool_RootSet, pOperationBaseClass->GetTabName());
					else
						pOperationBaseClass->CreateGeometricalSetInAStructure(_spMechanicalPart, pOperationBaseClass->GetTabName());


					if (SUCCEEDED(pOperationBaseClass->InstantiateUDF(_spPrtCont, listOfInputsToReplace, ProcessToolOperationsBaseClass::PackageType::Bead))) //package type is not used anymore
					{

						pOperationBaseClass->SetIndexUDFActive(_udfTypeIndexFromCombo);
						pOperationBaseClass->SetIndexUDFOld(_udfTypeIndexFromCombo_Previous);

						CATDlgMultiList *pMultiListInputParm = pTabDialog->GetMultiListInputParam();
						CATDlgMultiList *pMultiListCalculated = pTabDialog->GetMultiListCalculatedParam();

						pOperationBaseClass->GetUDFParametersInfo(pMultiListInputParm, pMultiListCalculated); //when UDF is instantiated its parameters which are to be shown(from NLS) in multilist will be displayed

						CATBaseUnknown_var spBeadUDF = pOperationBaseClass->GetUDFInstance();
						CATBaseUnknown_var spGeomSet = pOperationBaseClass->GetGeometricalSet();
						if (!!spBeadUDF && !!spGeomSet)
							MRFGenericUtils::ChangeMechanicalFather(spBeadUDF, spGeomSet);

						MRFGenericUtils::ShowInformationMessage("UDF Instantiation Successful");

						MRFGenericUtils::UpdateGivenComponent(spGeomSet);

						//pOperationBaseClass->ReplaceOldUDFWithNewUDF();
						/*if (pTabDialog)
							pTabDialog->ActivateTabPage(From_Bead_Tab);*/

						this->ActivateNextTabPage(index);

					}
					else //this else condition helps to delete the craeted package geometrical set if the instantiation is failed
					{
						CATIUseEntity_var spGeomSetDeleteEntity = pOperationBaseClass->GetGeometricalSet();
						if (!!spGeomSetDeleteEntity)
						{
							DataCommonProtocolServices::Delete(spGeomSetDeleteEntity);
							pOperationBaseClass->SetGeometricalSet(NULL_var);

						}
					}


				}
			}
		}


	}
}

