//======================CheckUDFInstantiated==================================//
// this functions helpsa to check whether the UDF is already instantiated or not
bool MRFProcessToolsCmd::CheckUDFInstantiated(CATUnicodeString iUsefulData)
{
	bool isUDFFound = false;

	if (_pMRFProcessToolsDlg)
	{

		int index = _pMRFProcessToolsDlg->GetTabContainer()->GetSelectedPage();

		if (index < 0)
			return isUDFFound;


		index = index + 1; //since tab index starts from 0 but the info of tab store in a ptr list where index starts from one so add one to its index;

		if (_pListOfProcessToolsOperationsBaseClass.Size() > 0 && _pListOfGenericDialog.Size() > 0)
		{
			ProcessToolOperationsBaseClass* pOperationBaseClass = (ProcessToolOperationsBaseClass*)_pListOfProcessToolsOperationsBaseClass[index];
			GenericTabDialog* pTabDialog = (GenericTabDialog*)_pListOfGenericDialog[index];

			if (pOperationBaseClass && pTabDialog)
			{
				if (!pOperationBaseClass->IsUDFInstantiated())
				{
					MRFGenericUtils::ShowErrorMessage("Instantiate UDF Before Importing Parameters\n");
				}
				else
					isUDFFound = true;
			}
		}
	}

	return isUDFFound;
}
