//=======================NavigateTabPage================================================================================================//
// Navigate or move to next or previous tab when next opr prev push button is clicked
void MRFProcessToolsCmd::NavigateTabPage(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	CATDlgTabContainer* tabContainer = NULL;
	char* temp = (char*)iUsefulData;
	if (_pMRFProcessToolsDlg)
	{
		tabContainer = _pMRFProcessToolsDlg->GetTabContainer();

		if (tabContainer)
		{
			int currentIndx = tabContainer->GetSelectedPage();

			if (currentIndx < 0)
				return;

			if (temp == From_NextTab)
			{
				int indexToSet = 0, totalPageCount = 0;
				totalPageCount = tabContainer->GetPageCount();
				
				if(totalPageCount > currentIndx)
					tabContainer->SetSelectedPage(currentIndx + 1, 1);
			}
			else if (temp == From_PrevTab)
			{
				if(currentIndx != 0)
					tabContainer->SetSelectedPage(currentIndx - 1, 1);
			}
		}
	}
}
