//==========================CreateNESCurveFeature=====================================//
//this function helps to create NESCurve Feature from the UDF(parameters) and matlab exe. 
// matlab exe execution is implemented in CATIFMFeatureBehaivour class"MEFNESCurveBehaviour"
void MRFProcessToolsCmd::CreateNESCurveFeature(MRFINESCurve_var &spNESCurveFeat)
{
	if (_pMRFProcessToolsDlg)
	{

		int index = _pMRFProcessToolsDlg->GetTabContainer()->GetSelectedPage();

		if (index < 0)
			return;

		index = index + 1; //since tab index starts from 0 but the info of tab store in a ptr list where index starts from one so add one to its index;

		if (_pListOfProcessToolsOperationsBaseClass.Size() > 0 && _pListOfGenericDialog.Size() > 0)
		{
			ProcessToolOperationsBaseClass* pOperationBaseClass = (ProcessToolOperationsBaseClass*)_pListOfProcessToolsOperationsBaseClass[index];
			GenericTabDialog* pTabDialog = (GenericTabDialog*)_pListOfGenericDialog[index];

			if (pOperationBaseClass && pTabDialog)
			{
				if (pOperationBaseClass->GetIsToCreateFeature() && pOperationBaseClass->IsUDFInstantiated())
				{
					if (!!_spMRFGSDFactory)
						_spMRFGSDFactory->CreateNESCurve(spNESCurveFeat);
					else
						return;

					if (!!spNESCurveFeat)
					{
						CATBaseUnknown_var spUDFInst = pOperationBaseClass->GetUDFInstance();
						if (!!spUDFInst)
						{
							spNESCurveFeat->SetReferenceUDF(spUDFInst);


							CATIAlias_var spFeatAlias = spNESCurveFeat;
							if (!!spFeatAlias)
							{
								spFeatAlias->SetAlias(pOperationBaseClass->GetFeatureCreatedName()); //Set the feature name read from nls for apex instantiation properly
								pOperationBaseClass->SetFeatureCreated(spNESCurveFeat);

							}


							CATBaseUnknown_var spGeomSet = pOperationBaseClass->GetGeometricalSet();

							if (!!spGeomSet)
								MRFGenericUtils::UpdateFeature(spNESCurveFeat, spGeomSet, TRUE);
							else
								MRFGenericUtils::UpdateFeature(spNESCurveFeat, _spMechanicalPart, TRUE);


						}

					}
				}
				else
				{
					MRFGenericUtils::ShowErrorMessage("Instantiate UDF before Creating a NES Feature");
				}

			}
		}
	}

}
