//=======================ReadNLSTabInfoFromConfigFile=====================//
// Reads the NLS configuration info from the config file
void MRFProcessToolsCmd::ReadNLSTabInfoFromConfigFile(CATUnicodeString configFileName, CATUnicodeString configFolderName)
{
	char *folderPathList = NULL;
	CATUnicodeString strTemp, strFile;
	bool folderPathFound = false;
	CATUnicodeString folderPathNLS;
	if (CATGetEnvValue("CATMsgCatalogPath", &folderPathList) == CATLibSuccess)
	{
		strTemp = folderPathList;

		CATUnicodeString msg = "The below file does not exists\n";

		stringstream fileStream(strTemp.ConvertToChar());
		while (fileStream.good() && folderPathFound == false)
		{
			string parmName;
			getline(fileStream, parmName, ';');
			folderPathNLS  = parmName.c_str();

			int charCountBeforeAddingExtension = 0;

			if (folderPathNLS != "")
			{
				folderPathNLS.Append("\\");
				folderPathNLS.Append(configFolderName);
				
			}

			CATUnicodeString temp = folderPathNLS;
			temp.Append("\\");
			temp.Append(configFileName);
			temp.Append(".CATNls");

			int accessMode = 0;
			if (CATFileAccess(temp.ConvertToChar(), accessMode) == CATLibSuccess)
			{
				folderPathFound = true;
			}
			else
			{
				msg.Append(temp);

			}
		}
	}

	if (!folderPathFound)
		return;

	folderPathNLS.ReplaceAll("\\", "/");

	int index = 0;
	CATMsgCatalog msgCatalog;
	index = msgCatalog.LoadMsgCatalog(configFileName.ConvertToChar(), folderPathNLS.ConvertToChar());
	_configFilePath = folderPathNLS;

	if (index == 0)
	{
		MRFGenericUtils::ShowErrorMessage("Please select any process tool type and click on start");
		return;

	}

	
	CATString nlsName, nls_TabInitializer, nls_TabCount;

	nlsName = configFileName;

	nls_TabInitializer = "Tab.";

	nls_TabCount = nls_TabInitializer;
	nls_TabCount.Append("Count");

	CATUnicodeString  profileCountAsStr;
	int UDFCount = 0;
	profileCountAsStr = (msgCatalog.GetCatalogMsg(nls_TabCount)).BuildMessage();
	profileCountAsStr.ConvertToNum(&UDFCount, "%d");

	bool atleatOneProfileFound = false;

	int UDFFound_Count = 0;
	for (int i = 1; i <= UDFCount; i++)
	{
		CATUnicodeString profileName = nls_TabInitializer, CountAsStr, tabName, tabIndex, tabNLSFile, tabIsDependant, 
			tabIsToCreateFeature, tabListOfDepIndex, tabFeatName;

		CountAsStr.BuildFromNum(i);
		profileName.Append(CountAsStr);

		tabName = profileName;
		tabName.Append(".Name");

		tabIndex = profileName;
		tabIndex.Append(".Index");

		tabNLSFile = profileName;
		tabNLSFile.Append(".NLS");

		tabIsDependant = profileName;
		tabIsDependant.Append(".Dependant");

		tabIsToCreateFeature = profileName;
		tabIsToCreateFeature.Append(".IsToCreateFeature");

		tabListOfDepIndex = profileName;
		tabListOfDepIndex.Append(".Dependant.Index");

		tabFeatName = profileName;
		tabFeatName.Append(".Feature_Name");


		tabName = (msgCatalog.GetCatalogMsg(tabName.ConvertToChar())).BuildMessage();
		tabIndex = (msgCatalog.GetCatalogMsg(tabIndex.ConvertToChar())).BuildMessage();
		tabNLSFile = (msgCatalog.GetCatalogMsg(tabNLSFile.ConvertToChar())).BuildMessage(); 
		tabIsDependant = (msgCatalog.GetCatalogMsg(tabIsDependant.ConvertToChar())).BuildMessage();
		tabIsToCreateFeature = (msgCatalog.GetCatalogMsg(tabIsToCreateFeature.ConvertToChar())).BuildMessage(); 
		tabListOfDepIndex = (msgCatalog.GetCatalogMsg(tabListOfDepIndex.ConvertToChar())).BuildMessage(); 
		tabFeatName = (msgCatalog.GetCatalogMsg(tabFeatName.ConvertToChar())).BuildMessage();

		if (tabName == "")
			continue;

		ConfigurationFileInfo *_pTabInfo = new ConfigurationFileInfo();

		_pTabInfo->_strTabName = tabName;
		_pTabInfo->_strIndex = tabIndex;
		_pTabInfo->_strNLSName = tabNLSFile;
		_pTabInfo->_strFeatureName = tabFeatName;
		_pTabInfo->_strNLSPath = configFolderName;

		if (tabIsDependant.Compare("True") == 1 || tabIsDependant.Compare("True") == 2)
		{
			_pTabInfo->isDependant = true;

			string inputParm = tabListOfDepIndex.ConvertToChar();
			stringstream  fileStream(inputParm);

			while (fileStream.good())
			{
				string parmName;
				getline(fileStream, parmName, ',');
				CATUnicodeString temp = parmName.c_str();

				if (temp != "")
				{
					int indexOfTabDependant = 0;
					temp.ConvertToNum(&indexOfTabDependant);

					int currentTabIndex = 0;
					tabIndex.ConvertToNum(&currentTabIndex);

					if (indexOfTabDependant > 0 && indexOfTabDependant < currentTabIndex) //The dependant tab index should be less than the current tab index because dependancy is always from previous package
						_pTabInfo->_listOfDependancyIndex.Append(indexOfTabDependant);
					else
					{
						MRFGenericUtils::ShowErrorMessage("Invalid Index Information in Config File");
					}
				}
				

			}


		}

		if (tabIsToCreateFeature.Compare("True") == 1 || tabIsToCreateFeature.Compare("True") == 2)
			_pTabInfo->isToCreateFeature = true;



		_pListOfConfigFileInfo.Append(_pTabInfo);
	}

}
