//=======================BuildUIFromConfigFile====================//
// this function helps to build the Generic UI
void MRFProcessToolsCmd::BuildUIFromConfigFile()
{
	if (!_pMRFProcessToolsDlg)
		return;

	CATDlgTabContainer *pContainer = NULL;
	pContainer = _pMRFProcessToolsDlg->GetTabContainer();
	if (pContainer)
	{
		int totalTabCount = _pListOfConfigFileInfo.Size();

		if (totalTabCount > 0)
		{
			for (int i = 1; i <= totalTabCount; i++)
			{
				bool tabIndexFoundInOrder = false;
				int notFoundIndex = 0;
				for (int j = 1; j <= totalTabCount; j++)
				{
					ConfigurationFileInfo *pConfigFileInfo = (ConfigurationFileInfo *)_pListOfConfigFileInfo[j]; // retrieve the config file info
					if (pConfigFileInfo == NULL)
						continue;

					CATUnicodeString nlsName = pConfigFileInfo->_strNLSName;
					CATUnicodeString featureName = pConfigFileInfo->_strFeatureName;
					bool isToCreateFeature = pConfigFileInfo->isToCreateFeature;
					int index = 0;
					pConfigFileInfo->_strIndex.ConvertToNum(&index);
					notFoundIndex = i;
					if (index == i) //this condition helps to check the index from nls and place the ui in ascendign order like index'; 1,2,3,4 even though defined not in order.
					{
						tabIndexFoundInOrder = true;
						GenericTabDialog *pDialog = new GenericTabDialog(pContainer);
						if (pDialog)
						{
							pDialog->BuildPackage(index, pConfigFileInfo->_strTabName, nlsName, _configFilePath,isToCreateFeature);

							_pListOfGenericDialog.Append(pDialog); //to store all the tab widgets in a list

							ProcessToolOperationsBaseClass *pBaseOperation = new ProcessToolOperationsBaseClass(index);
							if (pBaseOperation)
							{
								pBaseOperation->ReadNLSAtStart(nlsName,_configFilePath);
								pBaseOperation->SetIsToCreateFeature(isToCreateFeature);
								pBaseOperation->SetFeatureName(featureName);
								pBaseOperation->SetTabName(pConfigFileInfo->_strTabName);

								_pListOfProcessToolsOperationsBaseClass.Append(pBaseOperation);

							}

							this->AddSignalsAndSlotsToGenericWidgets(pDialog);
							
							break;
						}
					}
					else
						continue;
				}

				if (tabIndexFoundInOrder == false) //if index 1 is found and if user have defined index 3, 4 but not 2. then 2 is the missing index then it will through error.
				{
					CATUnicodeString strIndex;
					strIndex.BuildFromNum(i);
					MRFGenericUtils::ShowErrorMessage("The Given Index Count Not Found " + strIndex);
				}
			}
		}
	}
	CATUnicodeString strName;
	CATIAlias_var spAlias = _spXYPlane;
	if (NULL_var != spAlias)
	{
		strName = spAlias->GetAlias();

		_pMRFProcessToolsDlg->UpdateSelectorList(FromProcessXYPlaneSelector, strName);

	}

}
