//========================AddSignalsAndSlotsToGenericWidgets=====================================//
// this function creates the various signals and slots mechanism for the widgets available under the generic UI.
void MRFProcessToolsCmd::AddSignalsAndSlotsToGenericWidgets(GenericTabDialog* pDialog)
{
	if (!pDialog)
		return;

	CATDlgCombo *pComboUDFType = pDialog->GetComboBoxUDFType();
	if (pComboUDFType)
	{
		AddAnalyseNotificationCB(pComboUDFType, pComboUDFType->GetComboModifyNotification(), (CATCommandMethod)&MRFProcessToolsCmd::OnComboBeltSelected, NULL);
		AddAnalyseNotificationCB(pComboUDFType, pComboUDFType->GetComboSelectNotification(), (CATCommandMethod)&MRFProcessToolsCmd::OnComboBeltSelected, NULL);

	}

	CATDlgPushButton *pInstantiatePushButton = pDialog->GetPushButtonInstantiate();
	if (pInstantiatePushButton)
	{
		AddAnalyseNotificationCB(pInstantiatePushButton, pInstantiatePushButton->GetPushBActivateNotification(), (CATCommandMethod)&MRFProcessToolsCmd::OnInstantiatePushButton_Belt_Clicked, NULL);
	}

	CATDlgPushButton *pImportParmPushButton = pDialog->GetPushButtonImportExcelParam();
	if (pImportParmPushButton)
	{
		AddAnalyseNotificationCB(pImportParmPushButton, pImportParmPushButton->GetPushBActivateNotification(), (CATCommandMethod)&MRFProcessToolsCmd::OnImportParamsPushButtonClicked, NULL);
	}
	
	CATDlgPushButton *pCreateNESPushButton = pDialog->GetPushButtonCreateFeature();
	if (pCreateNESPushButton)
	{
		AddAnalyseNotificationCB(pCreateNESPushButton, pCreateNESPushButton->GetPushBActivateNotification(), (CATCommandMethod)&MRFProcessToolsCmd::OnCreateNESPlyLinePushButtonClicked, NULL);
	}

	CATDlgSpinner *pSPinner = pDialog->GetSpinnerParamValue();
	if (pSPinner)
	{
		AddAnalyseNotificationCB(pSPinner, pSPinner->GetSpinnerModifyNotification(), (CATCommandMethod)&MRFProcessToolsCmd::ValuateParameterOnSpinnerEdited, NULL);
	}

	CATDlgMultiList *pMultiList = pDialog->GetMultiListInputParam();
	if (pMultiList)
	{
		AddAnalyseNotificationCB(pMultiList, pMultiList->GetListSelectNotification(), (CATCommandMethod)&MRFProcessToolsCmd::ValuateSpinnerOnMultiListSelected, NULL);
	}

}
