//========================For Edit Mode Starts=================================================//
//========================ReadRootGeomSet============================================//
//Reads the Root geometrical Set and the package info from the aggregated geom set if UDF is instantiated already and available under the geom set
void MRFProcessToolsCmd::ReadRootGeomSet(const CATBaseUnknown_var &spRootGeomSet)
{
	if (!!_spGSMTool_RootSet)
	{
		HRESULT rc = E_FAIL;
		CATIUseEntity *pUseEntityOnFirstInstance = NULL;
		rc = _spGSMTool_RootSet->QueryInterface(IID_CATIUseEntity, (void**)& pUseEntityOnFirstInstance);
		if (SUCCEEDED(rc))
		{
			rc = DataCommonProtocolServices::Delete(pUseEntityOnFirstInstance);
			pUseEntityOnFirstInstance->Release(); pUseEntityOnFirstInstance = NULL;

			_spGSMTool_RootSet->Release(); _spGSMTool_RootSet = NULL;
		}
	}

	CATIGSMTool_var spGsmTool = spRootGeomSet;
	if (!!spGsmTool)
	{
		_spGSMTool_RootSet = spRootGeomSet;

		if (_pMRFProcessToolsDlg)
			_pMRFProcessToolsDlg->UpdateSelectorList(FromProcessGeomSetSelector, MRFGenericUtils::GetAliasName(spRootGeomSet));

		CATIBodyRequest_var  spBodyReqRootGeomSet = spGsmTool;
		CATListValCATBaseUnknown_var listOfGeomSetUnderRootSet;
		if (!!spBodyReqRootGeomSet)
		{
			spBodyReqRootGeomSet->GetDirectBodies(listOfGeomSetUnderRootSet);
		}

		if (listOfGeomSetUnderRootSet.Size() > 0)
		{
			for (int i = 1; i <= listOfGeomSetUnderRootSet.Size(); i++)
			{
				CATBaseUnknown_var spGeomSet = listOfGeomSetUnderRootSet[i];
				if (!!spGeomSet)
				{
					ReadPackageInfoFromGeomSet(spGeomSet, i);
				}
				else
					continue;
			}
		}

	}

	this->EnableOrDisableTab();
}
