//========================ReadPackageInfoFromGeomSet===================================================================//
//The name of the tab and geom set should be same, then it searches for UDF under it. If UDF is found its info is retrieved and set under the UI
bool MRFProcessToolsCmd::ReadPackageInfoFromGeomSet(const CATBaseUnknown_var &spPackageGeomSet, int indexOfGeomSetFromTree)
{
	bool isPackageInfoFound = false;
	CATIGSMTool_var spGsmTool = spPackageGeomSet;
	if (!!spGsmTool)
	{
		CATIBodyRequest_var  spBodyReqRootGeomSet = spGsmTool;
		if (!!spBodyReqRootGeomSet)
		{
			if (_pListOfProcessToolsOperationsBaseClass.Size() > 0 && _pListOfProcessToolsOperationsBaseClass.Size() >= indexOfGeomSetFromTree)
			{
				ProcessToolOperationsBaseClass *pBaseClass = NULL;
				pBaseClass = (ProcessToolOperationsBaseClass*)_pListOfProcessToolsOperationsBaseClass[indexOfGeomSetFromTree];
				GenericTabDialog* pTabDialog = NULL;
				pTabDialog = (GenericTabDialog*)_pListOfGenericDialog[indexOfGeomSetFromTree];

				if ( NULL != pBaseClass && pTabDialog)
				{
					CATUnicodeString packageName = pBaseClass->GetTabName(), geomSetName = MRFGenericUtils::GetAliasName(spPackageGeomSet);

					if (packageName.Compare(geomSetName) == 2 && pBaseClass != NULL)
					{
						isPackageInfoFound = true;
						pBaseClass->SetGeometricalSet(spPackageGeomSet);
						GetUDFInstanceUnderGeomSet(spPackageGeomSet,&pBaseClass);

						CATDlgMultiList *pMultiListInputParm = pTabDialog->GetMultiListInputParam();
						CATDlgMultiList *pMultiListCalculated = pTabDialog->GetMultiListCalculatedParam();
						CATDlgCombo *pComboBox = pTabDialog->GetComboBoxUDFType();
						if (pComboBox)
						{
							pComboBox->SetSelect(this->_udfTypeIndexFromCombo - 1); //decrement one to set proper combo inedx

						}
						if (NULL != pBaseClass)
						{
							pBaseClass->GetUDFParametersInfo(pMultiListInputParm, pMultiListCalculated); //when UDF is instantiated its parameters which are to be shown(from NLS) in multilist will be displayed

							if (pBaseClass->GetIsToCreateFeature())
							{
								CATUnicodeString featureName = pBaseClass->GetFeatureCreatedName();
								CATBaseUnknown_var spFeatureFound;
								MRFGenericUtils::FindFeatureUnderGeomSet(spPackageGeomSet, featureName, spFeatureFound);

								if (!!spFeatureFound)
									pBaseClass->SetFeatureCreated(spFeatureFound);
								else
								{
									CATUnicodeString msg = "Feature is not Created for the below package\n";
									msg.Append(packageName);

									MRFGenericUtils::ShowErrorMessage(msg);
								}
							}
						}
					}
					else
					{
						MRFGenericUtils::ShowErrorMessage("Package Not found at correct index\n Nls is modified or geomset is modified");
						return isPackageInfoFound;
					}
				}
			}
		}

	}

	return isPackageInfoFound;
}
//=======================================================================================================================//

//=====================================GetUDFInstanceUnderGeomSet===================================================================//
// check if the geom set is having the UDF by checking its type and if it is UDF and name is found in the current NLS info file it is retrieved and set in combo box
CATBaseUnknown_var MRFProcessToolsCmd::GetUDFInstanceUnderGeomSet(const CATIBodyRequest_var &spPackageGeomSet,ProcessToolOperationsBaseClass **pBaseClass)
{
	CATBaseUnknown_var spUDFInst; bool udfInstFound = false;
	if (!!spPackageGeomSet)
	{
		CATListValCATBaseUnknown_var spListOfFetaures;
		spPackageGeomSet->GetResults("MfDefault3DView", spListOfFetaures);

		if (spListOfFetaures.Size() > 0)
		{
			for (int i = 1; i <= spListOfFetaures.Size() && udfInstFound == false; i++)
			{
				CATIUdfFeatureInstance_var spUDFInstnce = spListOfFetaures[i];
				if (!!spUDFInstnce)
				{
					CATUnicodeString udfName = MRFGenericUtils::GetAliasName(spUDFInstnce);
					int index = -1;

					index = udfName.SearchSubString(".", 0, CATUnicodeString::CATSearchMode::CATSearchModeBackward);
					if (index == -1)
					{
						index = 0;
					}

					udfName = udfName.SubString(0, index);

					int udfIndexToSetInCombo = (*pBaseClass)->GetUDFIndexToSetInComboBox(udfName);
					if (udfIndexToSetInCombo != -1)
					{
						udfInstFound = true;
						this->_udfTypeIndexFromCombo = udfIndexToSetInCombo;
						(*pBaseClass)->SetUDFIndexFromComboBox(_udfTypeIndexFromCombo);
						(*pBaseClass)->SetIndexUDFActive(_udfTypeIndexFromCombo);
						(*pBaseClass)->SetUDFInstanceEditMode(_udfTypeIndexFromCombo, spUDFInstnce);
					}
				}
				else
					continue;
			}
		}
		else
			return spUDFInst;

	}

	return spUDFInst;
}
