//========================ValuateParameterOnSpinnerEdited============================================//
// This function helps to make changes in the instantiated udf parameters when spinner value is edited by comparing the name of the parameter
void MRFProcessToolsCmd::ValuateMultiListOnParamFrameEdited(CATCallbackEvent iPublishedEvent, void * iPublishingObject, CATNotification * iNotification, CATSubscriberData iClientData, CATCallback iCallback)
{

	if (_spParamEditedFromFrame == NULL_var)
		return;


	if (_pMRFProcessToolsDlg)
	{
		CATDlgMultiList *pMultiListInputParm = NULL;

		int index = _pMRFProcessToolsDlg->GetTabContainer()->GetSelectedPage();

		if (index < 0)
			return;

		index = index + 1; //since tab index starts from 0 but the info of tab store in a ptr list where index starts from one so add one to its index;

		if (_pListOfProcessToolsOperationsBaseClass.Size() > 0 && _pListOfGenericDialog.Size() > 0)
		{
			ProcessToolOperationsBaseClass* pOperationBaseClass = (ProcessToolOperationsBaseClass*)_pListOfProcessToolsOperationsBaseClass[index];
			GenericTabDialog* pTabDialog = (GenericTabDialog*)_pListOfGenericDialog[index];

			if (pOperationBaseClass && pTabDialog)
			{
				pMultiListInputParm = pTabDialog->GetMultiListInputParam();

				pMultiListInputParm->SetColumnItem(2, _spParamEditedFromFrame->Show(), _multiListIndexSelectedForEdit, CATDlgDataModify);

			}
		}
	}
}
