//--------------------------------------------------------------------
// MRFProcessToolsCmd::EnableOrDisableTab ()
//Enable Or Disable Tab in the dialog
//--------------------------------------------------------------------
void MRFProcessToolsCmd::ActivateNextTabPage(int previousIndex)
{
	int nextIndex = 0;

	if (previousIndex > 0)
		nextIndex = previousIndex + 1;

	if (_pMRFProcessToolsDlg)
	{
		CATDlgTabContainer* pTabCont =  _pMRFProcessToolsDlg->GetTabContainer();
		if (pTabCont)
		{
			
			if (nextIndex <= pTabCont->GetPageCount())
			{
				GenericTabDialog* pTabDialog = (GenericTabDialog*)_pListOfGenericDialog[nextIndex];
				if (pTabDialog)
					pTabDialog->GetTabPage()->SetSensitivity(CATDlgEnable);

			}
		}
	}

}
//--------------------------------------------------------------------
// MRFProcessToolsCmd::EnableOrDisableTab ()
//Enable Or Disable Tab in the dialog
//--------------------------------------------------------------------
void MRFProcessToolsCmd::EnableOrDisableTab()
{
	int pageCount = 0;
	bool isUDFInstantiatedForPrevPackage = false;
	if (_pMRFProcessToolsDlg)
	{
		CATDlgTabContainer* pTabCont = _pMRFProcessToolsDlg->GetTabContainer();
		if (pTabCont)
		{
			pageCount = pTabCont->GetPageCount();

			if (pageCount > 0 && _pListOfGenericDialog.Size() >= pageCount && _pListOfProcessToolsOperationsBaseClass.Size() >= pageCount)
			{
				for (int i = 1; i <= pageCount; i++)
				{
					ProcessToolOperationsBaseClass *pBaseClass = (ProcessToolOperationsBaseClass*)_pListOfProcessToolsOperationsBaseClass[i];
					if (pBaseClass)
					{
						if (pBaseClass->IsUDFInstantiated())
						{
							isUDFInstantiatedForPrevPackage = true;

							GenericTabDialog* pTabDialog = (GenericTabDialog*)_pListOfGenericDialog[i];
							if (pTabDialog)
								pTabDialog->GetTabPage()->SetSensitivity(CATDlgEnable);
						}
						else if (isUDFInstantiatedForPrevPackage == true)
						{
							if (_pListOfGenericDialog.Size() >= i + 1)
							{

								GenericTabDialog* pTabDialog = (GenericTabDialog*)_pListOfGenericDialog[i];
								if (pTabDialog)
									pTabDialog->GetTabPage()->SetSensitivity(CATDlgEnable);
							}

							isUDFInstantiatedForPrevPackage = false;

						}
					}
					
				}
			}
		}
	}

}